import React, { useRef } from 'react';

function FocusInput() {
  const inputRef = useRef();

  const handleClick = () => {
    inputRef.current.focus();
  };

  return (
    <div>
      <input type="text" ref={inputRef} placeholder="Buraya klik edin" />
      <button onClick={handleClick}>Inputa fokus ver</button>
    </div>
  );
}

console.log('useRef ilə DOM referansı yaradıldı');

import React, { useRef, useEffect } from 'react';

function Counter() {
  const renderCount = useRef(0);

  useEffect(() => {
    renderCount.current = renderCount.current + 1;
  });

  return <p>Komponent {renderCount.current} dəfə render olundu</p>;
}

console.log('useRef ilə dəyişməyən konteyner yaradıldı');

import React, { useRef, useImperativeHandle, forwardRef } from 'react';

const FancyInput = forwardRef((props, ref) => {
  const inputRef = useRef();

  useImperativeHandle(ref, () => ({
    focus: () => {
      inputRef.current.focus();
    },
    clear: () => {
      inputRef.current.value = '';
    }
  }));

  return <input ref={inputRef} type="text" placeholder="Buraya yazın" />;
});

function Parent() {
  const fancyInputRef = useRef();

  const handleClick = () => {
    fancyInputRef.current.focus();
  };

  return (
    <div>
      <FancyInput ref={fancyInputRef} />
      <button onClick={handleClick}>Fokus ver</button>
    </div>
  );
}

console.log('useImperativeHandle ilə komponent yaradıldı');

